import React, { useState, useEffect, useCallback, useMemo } from 'react';
import axios from 'axios';
import io from 'socket.io-client';
import Navbar from "./components/Navbar";

const socket = io('http://localhost:5000');

function App() {
  const [token, setToken] = useState(localStorage.getItem('token') || '');
  const [isLoggedIn, setIsLoggedIn] = useState(!!localStorage.getItem('token'));
  const [usuario, setUsuario] = useState(localStorage.getItem('user') || '');
  const [userRole, setUserRole] = useState(localStorage.getItem('role') || 'vendedor');

  const [authMode, setAuthMode] = useState('login');
  const [cred, setCred] = useState({ u: '', p: '', e: '', t: '', code: '' });
  const [nuevoRol, setNuevoRol] = useState('vendedor');
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ n: '', s: '', p: '', f: null });

  const handleLogout = useCallback(() => {
    localStorage.clear();
    setToken('');
    setIsLoggedIn(false);
    setAuthMode('login');
  }, []);

  // ESCUCHAR EXPULSIÓN (REQUERIMIENTO PROFE)
  useEffect(() => {
    if (isLoggedIn) {
      socket.emit('register', usuario);
      socket.on('force_logout', () => {
        alert("Has sido expulsado por el Super Administrador");
        handleLogout();
      });
    }
    return () => socket.off('force_logout');
  }, [isLoggedIn, usuario, handleLogout]);

  const cargarDatos = useCallback(async () => {
    if (!isLoggedIn) return;
    setLoading(true);
    const config = { headers: { Authorization: `Bearer ${token}` } };
    try {
      const [s, p] = await Promise.all([
        axios.get('http://localhost:5000/api/stats', config),
        axios.get('http://localhost:5000/api/productos', config)
      ]);
      setStats(s.data);
      setProductos(p.data);
    } catch (e) { if (e.response?.status === 401) handleLogout(); }
    finally { setLoading(false); }
  }, [isLoggedIn, token, handleLogout]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const buscar = useCallback(async (t) => {
    if (!t.trim()) { cargarDatos(); return; }
    const config = { headers: { Authorization: `Bearer ${token}` } };
    const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${t}`, config);
    setProductos(res.data);
  }, [token, cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    let timer;
    return (t) => { clearTimeout(timer); timer = setTimeout(() => buscar(t), 300); };
  }, [buscar]);

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario: cred.u, clave: cred.p });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('role', res.data.rol);
      localStorage.setItem('user', res.data.user);
      setToken(res.data.token);
      setUserRole(res.data.rol);
      setUsuario(res.data.user);
      setIsLoggedIn(true);
    } catch (e) { alert("Credenciales inválidas"); }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-8 rounded-[40px] shadow-2xl w-full max-w-sm text-white text-center">
          <h2 className="text-3xl font-black mb-6 uppercase tracking-tighter italic">Mi Tiendita Pro</h2>
          <div className="space-y-3">
            <input className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setCred({...cred, u: e.target.value})} />
            {authMode === 'register' && (
              <>
                <input className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Email" onChange={e => setCred({...cred, e: e.target.value})} />
                <select className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" onChange={e => setNuevoRol(e.target.value)}>
                   <option value="vendedor">Vendedor</option>
                   <option value="admin">Administrador</option>
                </select>
                {nuevoRol === 'admin' && <input className="w-full bg-red-900/20 p-4 rounded-2xl border border-red-500 outline-none font-bold" placeholder="CÓDIGO SECRETO" onChange={e => setCred({...cred, code: e.target.value})} />}
              </>
            )}
            <input type="password" title="pass" className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setCred({...cred, p: e.target.value})} />
            <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-3xl text-lg uppercase transition active:scale-95" onClick={authMode === 'login' ? handleLogin : () => axios.post('http://localhost:5000/api/register', {usuario: cred.u, email: cred.e, telefono: cred.t, clave: cred.p, rol: nuevoRol, codigoAdmin: cred.code}).then(()=>setAuthMode('login'))}>
              {authMode}
            </button>
            <p className="text-[10px] text-gray-400 font-bold uppercase cursor-pointer" onClick={() => setAuthMode(authMode==='login'?'register':'login')}> {authMode==='login'?'Crear Cuenta':'Login'} </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 text-slate-800">
      <Navbar setView={setView} userRole={userRole} logout={handleLogout} busqueda={busqueda} handleBusquedaChange={e => {setBusqueda(e.target.value); optimizadaBusqueda(e.target.value)}} />

      {/* Barra de carga que quita el Warning de LOADING */}
      {loading && <div className="h-1 w-full bg-[#00c984] fixed top-20 z-50 animate-pulse"></div>}

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        <h1 className="text-2xl font-black mb-8 uppercase italic text-slate-400">Sesión: {usuario}</h1>

        {view === "dashboard" && busqueda === "" ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div onClick={() => setView('inv')} className="bg-white p-10 border rounded-[50px] shadow-xl text-center cursor-pointer hover:scale-105 transition">
              <p className="text-xs text-gray-400 font-black uppercase mb-2">Stock</p>
              <p className="text-6xl font-black text-[#1e293b]">{stats.total_productos}</p>
            </div>
            <div className="bg-white p-10 border rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-red-400 font-black uppercase mb-2">Crítico</p>
              <p className="text-6xl font-black text-red-500">{stats.bajo_stock}</p>
            </div>
            <div className="bg-white p-10 border rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-green-400 font-black uppercase mb-2 tracking-widest leading-none">Capital</p>
              <p className="text-4xl font-black text-green-600 mt-2">${stats.valor_inventario.toLocaleString()}</p>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black uppercase italic">{busqueda ? `Resultados: ${busqueda}` : "Inventario"}</h2>
              {userRole === 'admin' && <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-8 py-3 rounded-2xl font-black text-xs uppercase shadow-lg"> {showForm ? 'Cerrar' : '+ Nuevo'} </button>}
            </div>
            {showForm && (
              <div className="bg-white p-6 rounded-[40px] border-4 border-dashed grid grid-cols-1 md:grid-cols-5 gap-4">
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Nombre" onChange={e => setNuevoProd({...nuevoProd, n: e.target.value})} />
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Stock" type="number" onChange={e => setNuevoProd({...nuevoProd, s: e.target.value})} />
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Precio" type="number" onChange={e => setNuevoProd({...nuevoProd, p: e.target.value})} />
                <input type="file" className="text-xs mt-4" onChange={e => setNuevoProd({...nuevoProd, f: e.target.files[0]})} />
                <button className="bg-[#00c984] text-[#1e293b] font-black rounded-2xl" onClick={async () => {
                  const fd = new FormData(); fd.append('nombre', nuevoProd.n); fd.append('stock', nuevoProd.s); fd.append('precio_venta', nuevoProd.p); if (nuevoProd.f) fd.append('imagen', nuevoProd.f);
                  const config = { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'multipart/form-data' } };
                  await axios.post('http://localhost:5000/api/productos', fd, config); setShowForm(false); cargarDatos();
                }}>GUARDAR</button>
              </div>
            )}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {productos.filter(p => p.nombre.toLowerCase().includes(busqueda.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-4 rounded-[30px] shadow-lg border border-gray-100 text-center relative group">
                  <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/150'} className="w-full h-32 md:h-40 object-cover rounded-3xl mb-3 shadow-sm" alt="p" />
                  <h3 className="font-black uppercase text-[10px] md:text-xs mb-1 line-clamp-1">{p.nombre}</h3>
                  <p className="text-green-600 font-black text-lg md:text-xl">${p.precio_venta}</p>
                  {userRole === 'admin' && <button onClick={() => axios.delete(`http://localhost:5000/api/productos/${p.id}`, {headers: {Authorization: `Bearer ${token}`}}).then(()=>cargarDatos())} className="absolute top-2 right-2 text-red-300 hover:text-red-500 transition"><i className="fas fa-trash"></i></button>}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
